```cpp
int findMaxReverse(int n)
{
    if (checkReverse(n)) return n; // Case 0 deletions
    int result = -1;
    // Sau đó mới xét các trường hợp xóa 1, 2, ... chữ số
    // Cần một thuật toán đệ quy hoặc duyệt sâu để tìm tất cả các subsequence đối xứng
    // Hoặc sửa lại delDigit để nó thực sự tìm số đối xứng bằng cách xóa 'check' chữ số
    // Hiện tại, delDigit(n, 0) đang tìm số đối xứng bằng cách xóa 1 chữ số.
    // Cần một cách tiếp cận tổng quát hơn cho 'xóa con số bất kì'.
    result = delDigit(n, 0); // Đây thực chất là tìm số đối xứng bằng cách xóa 1 chữ số
    if (result != -1) return result;
    // Nếu cần xóa nhiều hơn, sẽ tiếp tục gọi delDigit(n, 1) cho 2 chữ số, v.v.
    return result;
}
