bool isDiagonalSymmetric(int matrix[][100], int n) {
    // Check main diagonal
    for (int i = 0; i < n; i++) {
        for (int j = i + 1; j < n; j++) {
            if (matrix[i][j] != matrix[j][i]) {
                return false; // Problematic: should continue to check anti-diagonal
            }
        }
    }
    // Check anti-diagonal
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n - i - 1; j++) {
            if (matrix[i][j] != matrix[n - j - 1][n - i - 1]) {
                return false; // Problematic: if main diagonal was symmetric, this still returns false
            }
        }
    }
    return true; // Only reached if BOTH are symmetric
}

