int ktraDgCheoPhu(int a[][10], int n)
{
    int b[100], c[100];
    int nb = 0, nc = 0;

    for (int i = 0; i < n; i++)
        for (int j = 0; j < n; j++)
        {
            if (i + j != n - 1)
            {
                if (i >= j )
                {
                    b[nb] = a[i][j];
                    nb += 1;
                }
                else if (j >= i)
                {
                    c[nc] = a[i][j];
                    nc += 1;
                }
            }

        }

    int l = 0, r = nb - 1;
    for (int i = 0; i < nb; i++)
    {
        if (b[l] != c[r]) return 1;
        l++ ; r--;
    }
    return 0;  
}

